        IERC20(wbtcAddress).forceApprove(adapter, amount);
        uint256 amountOut = IPerpExchange(adapter).tradeSpot(wbtcAddress, usdcAddress, amount);
        emit ProtocolInteraction("EXCHANGE_SPOT_SELL", usdcAddress, amountOut);
